import React, { useState } from 'react';
import axios from 'axios';

export default function Detector() {
  const [file, setFile] = useState(null);
  const [preview, setPreview] = useState(null);
  const [mode, setMode] = useState('classification');
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(false);

  const handleFileChange = (e) => {
    const selectedFile = e.target.files[0];
    setFile(selectedFile);
    setPreview(URL.createObjectURL(selectedFile));
    setData(null);
  };

  const uploadAndAnalyze = async () => {
    setLoading(true);
    const formData = new FormData();
    formData.append('file', file);
    formData.append('mode', mode);

    try {
      // Connect to Flask backend
      const res = await axios.post('http://localhost:5000/analyze', formData);
      setData(res.data);
    } catch (err) {
      alert("Network Error: Is the Flask server running on port 5000?");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{ padding: '40px', textAlign: 'center' }}>
      <h2>NeuroScanAI Hub</h2>
      
      <div style={{ marginBottom: '20px' }}>
        <select onChange={(e) => setMode(e.target.value)} value={mode} style={{ marginRight: '10px' }}>
          <option value="classification">Classification (H5)</option>
          <option value="segmentation">Segmentation (Keras)</option>
        </select>
        <input type="file" onChange={handleFileChange} accept="image/*" />
        <button onClick={uploadAndAnalyze} disabled={!file || loading}>
          {loading ? 'Analyzing...' : 'Run Analysis'}
        </button>
      </div>

      {preview && (
        <div style={{ position: 'relative', display: 'inline-block', border: '2px solid #333' }}>
          {/* Base MRI Image */}
          <img src={preview} alt="MRI" style={{ width: '400px', display: 'block' }} />
          
          {/* The Green Mask Overlay */}
          {data && data.mask && mode === 'segmentation' && (
            <img 
              src={data.mask} 
              alt="Mask" 
              style={{ 
                position: 'absolute', 
                top: 0, left: 0, width: '100%', height: '100%',
                opacity: 0.6,
                filter: 'hue-rotate(90deg) saturate(10) brightness(1.2)', // Visualizes mask as green
                pointerEvents: 'none'
              }} 
            />
          )}
        </div>
      )}

      {data && data.result && (
        <div style={{ marginTop: '20px', fontSize: '1.2rem', fontWeight: 'bold', color: '#2c3e50' }}>
          Result: {data.result}
          {data.confidence && <p>Confidence: {(data.confidence * 100).toFixed(2)}%</p>}
        </div>
      )}
    </div>
  );
}
